import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import Navbar from "../components/Navbar";

function MyBookings() {
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [paymentMethod, setPaymentMethod] = useState("card");
  const [paymentLoading, setPaymentLoading] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      navigate("/login");
      return;
    }

    fetchBookings();
  }, []);

  const fetchBookings = async () => {
    try {
      const token = localStorage.getItem("token");

      const response = await axios.get(
        "http://localhost:5000/api/bookings/my",
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      setBookings(response.data.bookings || []);
    } catch (err) {
      setError("Failed to load bookings");
    } finally {
      setLoading(false);
    }
  };

  const handleCancelBooking = async (bookingId) => {
    if (!window.confirm("Are you sure you want to cancel this booking?"))
      return;

    try {
      const token = localStorage.getItem("token");

      await axios.put(
        `http://localhost:5000/api/bookings/${bookingId}/cancel`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );

      fetchBookings();
    } catch (err) {
      alert("Failed to cancel booking");
    }
  };

  const openPaymentModal = (booking) => {
    setSelectedBooking(booking);
    setShowPaymentModal(true);
  };

  const closePaymentModal = () => {
    setShowPaymentModal(false);
    setSelectedBooking(null);
    setPaymentMethod("card");
  };

  const handlePayment = async () => {
    setPaymentLoading(true);
    setError("");

    try {
      const token = localStorage.getItem("token");

      await axios.post(
        "http://localhost:5000/api/payments",
        {
          bookingId: selectedBooking._id,
          paymentMethod,
        },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      closePaymentModal();
      fetchBookings();
    } catch (err) {
      setError(err.response?.data?.message || "Payment failed");
    } finally {
      setPaymentLoading(false);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case "confirmed":
        return "bg-green-100 text-green-800";
      case "pending":
        return "bg-yellow-100 text-yellow-800";
      case "cancelled":
        return "bg-red-100 text-red-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getPaymentStatusColor = (status) => {
    switch (status) {
      case "paid":
        return "bg-green-100 text-green-800";
      case "unpaid":
        return "bg-red-100 text-red-800";
      case "refunded":
        return "bg-blue-100 text-blue-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  if (loading) {
    return (
      <div>
        <Navbar />
        <div className="text-center py-20 text-2xl">
          Loading bookings...
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />

      <div className="bg-gradient-to-r from-blue-600 to-purple-600 py-8">
        <div className="container mx-auto px-4">
          <h1 className="text-4xl font-bold text-white">
            My Bookings
          </h1>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        {error && (
          <div className="bg-red-100 text-red-700 p-4 rounded mb-4">
            {error}
          </div>
        )}

        {bookings.length === 0 ? (
          <div className="bg-white p-12 rounded-2xl shadow text-center">
            <h2 className="text-2xl font-bold mb-4">
              No bookings yet
            </h2>
            <button
              onClick={() => navigate("/")}
              className="bg-blue-600 text-white px-6 py-3 rounded-lg"
            >
              Browse Events
            </button>
          </div>
        ) : (
          <div className="space-y-6">
            {bookings.map((booking) => (
              <div
                key={booking._id}
                className="bg-white rounded-2xl shadow p-6"
              >
                <div className="grid md:grid-cols-4 gap-6">

                  <img
                    src={
                      booking.event?.image ||
                      "https://via.placeholder.com/300x200"
                    }
                    alt={booking.event?.name}
                    className="w-full h-32 object-cover rounded-lg"
                  />

                  <div className="md:col-span-2">
                    <h3 className="text-2xl font-bold mb-3">
                      {booking.event?.name}
                    </h3>

                    {/* NEW: Contestant Name */}
                    {booking.contestantName && (
                      <p className="mb-2">
                        👤 <strong>Contestant:</strong>{" "}
                        {booking.contestantName}
                      </p>
                    )}

                    <p>🎫 {booking.numberOfTickets} Ticket(s)</p>
                    <p>
                      💰 ₹{booking.totalAmount}
                    </p>

                    <div className="flex gap-2 mt-4">
                      <span
                        className={`px-3 py-1 rounded-full text-xs font-semibold ${getStatusColor(
                          booking.status
                        )}`}
                      >
                        {booking.status.toUpperCase()}
                      </span>
                      <span
                        className={`px-3 py-1 rounded-full text-xs font-semibold ${getPaymentStatusColor(
                          booking.paymentStatus
                        )}`}
                      >
                        {booking.paymentStatus.toUpperCase()}
                      </span>
                    </div>
                  </div>

                  <div className="flex flex-col justify-center gap-3">
                    {booking.paymentStatus === "unpaid" &&
                      booking.status !== "cancelled" && (
                        <button
                          onClick={() => openPaymentModal(booking)}
                          className="bg-green-600 text-white px-4 py-2 rounded-lg"
                        >
                          Pay Now
                        </button>
                      )}

                    {booking.status !== "cancelled" && (
                      <button
                        onClick={() =>
                          handleCancelBooking(booking._id)
                        }
                        className="bg-red-600 text-white px-4 py-2 rounded-lg"
                      >
                        Cancel
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Payment Modal stays same as yours */}
    </div>
  );
}

export default MyBookings;
